INSERT INTO community_post (title, category, content, author, author_id, like_count, comment_count, collect_count, view_count, status, is_deleted, create_time, update_time) VALUES
('新手养猫必备指南', 'experience', '今天想和大家分享一下我的养宠经验，作为一个新手铲屎官，我总结了一些养猫的必备知识，希望能帮助到准备养猫的朋友们。', '爱猫达人', 1, 156, 23, 45, 342, 1, 0, '2026-05-01 10:30:00', '2026-05-01 10:30:00'),
('如何训练狗狗定点大小便', 'experience', '经过一段时间的摸索，总结出一些训练狗狗定点大小便的方法，希望对大家有帮助。训练需要耐心和正确的方法。', '铲屎官小明', 2, 234, 45, 67, 567, 1, 0, '2026-05-02 14:20:00', '2026-05-02 14:20:00'),
('猫咪疫苗接种全攻略', 'experience', '给大家分享一下猫咪疫苗接种的全攻略，包括接种时间、注意事项等。定期接种疫苗对猫咪的健康非常重要。', '宠物爱好者', 3, 189, 34, 56, 456, 1, 0, '2026-05-03 09:15:00', '2026-05-03 09:15:00'),
('狗狗日常护理小贴士', 'experience', '分享一些狗狗日常护理的小贴士，让你的狗狗保持健康和美丽。日常护理包括梳毛、清洁耳朵等。', '狗奴一枚', 4, 267, 45, 78, 678, 1, 0, '2026-05-04 16:45:00', '2026-05-04 16:45:00'),
('宠物饮食营养搭配建议', 'experience', '宠物的饮食非常重要，正确的营养搭配能让它们更健康。不同年龄段的宠物需要不同的营养配比。', '猫咪控', 5, 312, 56, 89, 789, 1, 0, '2026-05-05 11:20:00', '2026-05-05 11:20:00'),
('猫咪行为解读与训练', 'experience', '解读猫咪的各种行为，并分享一些训练技巧。理解猫咪的行为能帮助我们更好地与它们相处。', '宠物博主', 6, 245, 45, 67, 567, 1, 0, '2026-05-06 08:30:00', '2026-05-06 08:30:00'),
('如何给狗狗洗澡不抓狂', 'experience', '给狗狗洗澡是一件让人头疼的事，分享一些让狗狗乖乖洗澡的技巧。洗澡前的准备工作很重要。', '养宠新手', 7, 198, 34, 56, 456, 1, 0, '2026-05-07 15:40:00', '2026-05-07 15:40:00'),
('宠物牙齿护理的重要性', 'experience', '很多人忽略了宠物的牙齿护理，这其实非常重要。定期刷牙能预防很多口腔疾病。', '资深铲屎官', 8, 289, 56, 78, 789, 1, 0, '2026-05-08 13:10:00', '2026-05-08 13:10:00'),
('猫咪应激反应处理方法', 'experience', '猫咪应激反应很常见，分享一些处理方法和预防措施。应激反应可能导致猫咪生病。', '爱猫达人', 9, 167, 28, 45, 345, 1, 0, '2026-05-09 10:00:00', '2026-05-09 10:00:00'),
('狗狗社会化训练技巧', 'experience', '狗狗社会化训练非常重要，分享一些实用的训练技巧。社会化训练能让狗狗更友好。', '铲屎官小明', 10, 234, 45, 67, 567, 1, 0, '2026-05-10 17:30:00', '2026-05-10 17:30:00');
INSERT INTO community_post (title, category, content, author, author_id, like_count, comment_count, collect_count, view_count, status, is_deleted, create_time, update_time) VALUES
('猫咪突然不吃东西怎么办？', 'help', '最近遇到了一个问题，想请教一下各位铲屎官，我家猫咪突然不吃东西了，已经两天了，有点担心。', '宠物爱好者', 11, 45, 12, 8, 234, 1, 0, '2026-05-11 09:20:00', '2026-05-11 09:20:00'),
('狗狗频繁呕吐寻求帮助', 'help', '我家狗狗最近频繁呕吐，已经两天了，有没有人知道该怎么办？精神状态还可以，但就是不吃东西。', '狗奴一枚', 12, 67, 23, 12, 345, 1, 0, '2026-05-12 14:50:00', '2026-05-12 14:50:00'),
('求助：猫咪一直叫个不停', 'help', '我家猫咪最近一直叫个不停，尤其是晚上，有没有什么办法？感觉它有点焦虑。', '猫咪控', 13, 89, 34, 18, 456, 1, 0, '2026-05-13 11:15:00', '2026-05-13 11:15:00'),
('家里宠物打架怎么办？', 'help', '家里新来了一只猫咪，和原来的狗狗总是打架，求助！有没有什么办法让它们和平相处？', '宠物博主', 14, 56, 18, 12, 289, 1, 0, '2026-05-14 16:20:00', '2026-05-14 16:20:00'),
('猫咪乱尿问题求解决', 'help', '我家猫咪最近开始乱尿，已经清理了好几次了，求解决办法。之前一直很乖的。', '养宠新手', 15, 78, 28, 15, 398, 1, 0, '2026-05-15 08:45:00', '2026-05-15 08:45:00'),
('狗狗分离焦虑症怎么治？', 'help', '我家狗狗有严重的分离焦虑症，每次出门都叫得很厉害，回来家里被拆得乱七八糟。', '资深铲屎官', 16, 98, 36, 22, 512, 1, 0, '2026-05-16 13:30:00', '2026-05-16 13:30:00'),
('求助：宠物误食异物', 'help', '我家猫咪好像误食了异物，现在精神不太好，该怎么办？已经联系了兽医，但还没轮到。', '爱猫达人', 17, 45, 14, 8, 267, 1, 0, '2026-05-17 10:20:00', '2026-05-17 10:20:00'),
('猫咪掉毛严重怎么办', 'help', '春天到了，我家猫咪掉毛特别严重，有没有什么好办法？家里到处都是猫毛。', '铲屎官小明', 18, 67, 24, 14, 378, 1, 0, '2026-05-18 15:45:00', '2026-05-18 15:45:00'),
('狗狗皮肤病求助', 'help', '我家狗狗身上长了很多红点，好像很痒，求推荐治疗方法。已经去过医院但效果不太好。', '宠物爱好者', 19, 56, 16, 10, 289, 1, 0, '2026-05-19 09:00:00', '2026-05-19 09:00:00'),
('如何让宠物适应新环境', 'help', '刚领养了一只猫咪，它一直躲在角落里，怎么让它适应新环境？已经三天了还是不敢出来。', '狗奴一枚', 20, 78, 22, 16, 398, 1, 0, '2026-05-20 12:30:00', '2026-05-20 12:30:00');
INSERT INTO community_post (title, category, content, author, author_id, like_count, comment_count, collect_count, view_count, status, is_deleted, create_time, update_time) VALUES
('我家猫咪的奇葩睡姿', 'fun', '哈哈，我家主子今天又做了一件蠢事，给大家看看它的奇葩睡姿，简直是个睡神。', '猫咪控', 21, 156, 34, 45, 678, 1, 0, '2026-05-21 14:15:00', '2026-05-21 14:15:00'),
